    public void update()
    {
        boolean loadedAddressUpdated;

        if(this.LoadedPostalAddress != this.orig().LoadedPostalAddress)
        {
            loadedAddressUpdated = true;
        }

        next update();

        if(loadedAddressUpdated)
        {
            PurchTable purchTable;

            select firstonly purchTable where purchTable.TransportationDocument == this.RecId;

            if(purchTable.RecId)
            {
                purchTable.selectForUpdate(true);
                purchTable.UBSTaxRecalcFlag = purchTable.UBSTaxRecalcFlag == NoYes::Yes ? NoYes::No : NoYes::Yes;
                purchTable.update();
            }
        }
    }
